x;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n\n/* === THEME BUILDER FULL-BLEED OVERRIDES === */\n.et_pb_section_0_tb_body{background:#000432 !important;padding:0 !important;margin:0 !important;width:100% !important}\n.et_pb_row_0_tb_body{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column_0_tb_body{padding:0 !important;width:100% !important}\n.et_pb_post_content_0_tb_body{width:100% !important;max-width:100% !important}\n.et_pb_row_1_tb_body{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column_1_tb_body{width:100% !important;padding:0 !important}\n\n/* === PAGE-LEVEL DIVI WRAPPER RESETS === */\n.et_pb_section_0{background:#000432 !important;padding:0 !important;margin:0 !important}\n.et_pb_section_0 .et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_section_0 .et_pb_column{width:100% !important;padding:0 !important}\n.et_pb_section_0 .et_pb_code,.et_pb_section_0 .et_pb_code_inner{position:static !important;overflow:visible !important}\n\n/* === SPLIT SCREEN GRID === */\n.hero-split{\n  display:grid;\n  grid-template-columns:1fr 1fr;\n  min-height:calc(100vh - 80px);\n  margin-top:80px;\n  position:relative;\n  overflow:hidden;\n  background-color:#000432;\n  -webkit-font-smoothing:auto;\n  -moz-osx-font-smoothing:auto;\n  width:100vw;\n  margin-left:calc(-50vw + 50%);\n}\n\n/* === PANELS === */\n.hero-panel{\n  position:relative;\n  overflow:hidden;\n  padding:80px 60px;\n  display:flex;\n  flex-direction:column;\n  justify-content:center;\n}\n.hero-panel--factory{background:linear-gradient(165deg, rgb(15,20,25) 0%, rgb(26,38,50) 40%, rgb(0,8,100) 100%)}\n.hero-panel--partner{background:linear-gradient(165deg, rgb(0,175,240) 0%, rgb(0,60,200) 40%, rgb(0,60,200) 100%)}\n\n/* === SVG ILLUSTRATIONS === */\n.hero-svg-illustration{position:absolute;top:0;left:0;right:0;bottom:0;pointer-events:none;z-index:1;opacity:0.45}\n.hero-svg-illustration svg{width:100%;height:100%;display:block}\n\n/* === CONTENT === */\n.hero-content{position:relative;z-index:2;max-width:520px}\n\n/* === LABELS === */\n.hero-label{font-family:\'JetBrains Mono\',monospace !important;font-size:14px !important;font-weight:600 !important;text-transform:uppercase;letter-spacing:0.15em;line-height:1.6;color:#00AFF0;margin:0 0 24px;padding:0;display:flex;align-items:center;gap:12px}\n.hero-label::before{content:\'\';width:40px;height:1px;background:linear-gradient(90deg,transparent,#00AFF0);flex-shrink:0}\n.hero-label--partner{color:rgba(255,255,255,0.9)}\n.hero-label--partner::before{background:linear-gradient(90deg,transparent,rgba(255,255,255,0.9))}\n\n/* === TITLES === */\n.hero-title{font-family:\'Noto Sans\',sans-serif;font-size:clamp(32px,3.5vw,52px);font-weight:700;color:#fff;margin:0 0 24px;line-height:1.1;letter-spacing:-0.03em}\n.hero-title .hl-blue{color:#00AFF0}\n.hero-title .hl-gold{color:#fef3c7}\n\n/* === SUBTITLES === */\n.hero-subtitle{font-family:\'Noto Sans\',sans-serif !important;font-size:18px !important;font-weight:400 !important;color:rgba(255,255,255,0.75);margin:0 0 36px;line-height:1.75;max-width:500px}\n\n/* === BUTTONS === */\n.hero-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;line-height:1.6;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.4s cubic-bezier(0.4,0,0.2,1);text-decoration:none;display:inline-flex !important;align-items:center;position:relative;overflow:hidden;border:2px solid transparent;box-sizing:border-box}\n.hero-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.hero-btn:hover::before{left:100%}\n.hero-btn--primary{background:#006dac;color:#fff;box-shadow:0 4px 14px rgba(0,175,240,0.35);gap:8px}\n.hero-btn--primary:hover{background:#003CC8;transform:translateY(-2px);box-shadow:0 6px 20px rgba(0,175,240,0.45)}\n.hero-btn--ghost{background:rgba(255,255,255,0.15);color:#fff;border-color:rgba(255,255,255,0.9);backdrop-filter:blur(4px);-webkit-backdrop-filter:blur(4px);gap:8px}\n.hero-btn--ghost:hover{background:#fff;color:#0C4A6E;border-color:#fff}\n.hero-btn-row{display:flex;align-items:center;gap:12px;max-width:520px;font-size:16px;flex-wrap:wrap}\n.hero-btn-row .hero-btn--ghost{margin-left:12px}\n\n/* === STATS === */\n.hero-stats{display:flex;gap:40px;margin-top:48px;padding-top:32px;border-top:1px solid rgba(255,255,255,0.1);max-width:520px}\n.hero-stat-number{font-family:\'Noto Sans\',sans-serif;font-size:32px;font-weight:800;color:#00AFF0;line-height:1;margin-bottom:8px;letter-spacing:-0.02em}\n.hero-stat-number--white{color:#fff}\n.hero-stat-label{font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:400;color:rgba(255,255,255,0.85);text-transform:uppercase;letter-spacing:0.1em;line-height:1.6}\n\n/* === GRAIN TEXTURE OVERLAY === */\n.hero-grain{position:absolute;top:0;left:0;right:0;bottom:0;pointer-events:none;z-index:1}\n.hero-grain::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1;animation:hero-grain 8s steps(10) infinite}\n.hero-grain--partner::before{opacity:0.04;animation:none}\n\n/* === LIGHT LEAK === */\n.hero-light-leak{position:absolute;top:0;left:0;right:0;bottom:0;pointer-events:none;z-index:1}\n.hero-light-leak::after{content:\'\';position:absolute;top:-50%;right:-30%;width:80%;height:150%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.15) 0%,transparent 60%);pointer-events:none;z-index:1}\n\n/* === RESPONSIVE === */\n@media(max-width:1024px){\n  .hero-split{grid-template-columns:1fr;min-height:auto}\n  .hero-panel{min-height:70vh;padding:60px 40px}\n  .hero-stats{gap:24px;flex-wrap:wrap}\n  .hero-title{font-size:32px}\n  .hero-subtitle{font-size:16px}\n}\n@media(max-width:640px){\n  .hero-panel{padding:48px 24px;min-height:80vh}\n  .hero-stats{flex-direction:column;gap:24px}\n  .hero-btn-row{flex-direction:column}\n  .hero-btn{text-align:center}\n}\n\n/* === ADMIN BAR COMPENSATION === */\nbody.admin-bar .hero-split{margin-top:48px;min-height:calc(100vh - 80px)}\n\n/* === REDUCED MOTION === */\n@media(prefers-reduced-motion:reduce){\n  .hero-grain::before{animation:none}\n  .hero-btn::before{transition:none}\n  .hero-svg-illustration{opacity:0.25}\n}\n\n/* === GRAIN ANIMATION KEYFRAME === */\n@keyframes hero-grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-5%,-10%)}20%{transform:translate(-15%,5%)}30%{transform:translate(7%,-25%)}40%{transform:translate(-5%,25%)}50%{transform:translate(-15%,10%)}60%{transform:translate(15%,0%)}70%{transform:translate(0%,15%)}80%{transform:translate(3%,35%)}90%{transform:translate(-10%,10%)}}\n\n/* ===== LOGO MARQUEE SECTION ===== */\n.logobar-section{\n  background:linear-gradient(180deg, #f8fafc 0%, #ffffff 100%);\n  padding:60px 0;\n  -webkit-font-smoothing:auto;\n  -moz-osx-font-smoothing:auto;\n  font-size:16px;\n  overflow:hidden;\n  position:relative;\n  width:100%;\n  max-width:100vw;\n}\n.logobar-label{\n  font-family:\'JetBrains Mono\',monospace;\n  font-size:13px;\n  font-weight:500;\n  text-transform:uppercase;\n  letter-spacing:0.15em;\n  color:#5b6b80;\n  text-align:center;\n  line-height:1.6;\n  margin:0 0 48px;\n  padding:0;\n}\n.logobar-marquee-wrapper{\n  width:100%;\n  overflow:hidden;\n  position:relative;\n  padding:0;\n  margin:0 0 48px;\n  mask-image:linear-gradient(90deg, transparent, #000 8%, #000 92%, transparent);\n  -webkit-mask-image:linear-gradient(90deg, transparent, #000 8%, #000 92%, transparent);\n}\n.logobar-marquee{\n  display:flex;\n  gap:60px;\n  animation:logobar-scroll 35s linear infinite;\n  width:max-content;\n}\n.logobar-marquee:hover{\n  animation-play-state:paused;\n}\n@keyframes logobar-scroll{\n  0%{transform:translateX(0)}\n  100%{transform:translateX(-50%)}\n}\n.logobar-item{\n  display:flex;\n  align-items:center;\n  gap:24px;\n  flex-shrink:0;\n  transition:all 0.4s ease;\n}\n.logobar-logo{\n  height:108px;\n  max-width:126px;\n  display:flex;\n  align-items:center;\n  justify-content:center;\n  transition:filter 0.4s ease;\n  filter:grayscale(100%) opacity(0.45);\n}\n.logobar-item:hover .logobar-logo{\n  filter:grayscale(0%) opacity(1);\n}\n.logobar-placeholder{\n  width:108px;\n  height:108px;\n  border-radius:12px;\n  display:flex;\n  align-items:center;\n  justify-content:center;\n  color:#fff;\n  font-family:\'Noto Sans\',sans-serif;\n  font-size:32px;\n  font-weight:700;\n  letter-spacing:-0.02em;\n}\n.logobar-text{\n  display:flex;\n  flex-direction:column;\n  gap:4px;\n}\n.logobar-name{\n  font-family:\'Noto Sans\',sans-serif;\n  font-size:30px;\n  font-weight:600;\n  color:#334155;\n  opacity:0.55;\n  line-height:1.25;\n  transition:opacity 0.4s ease;\n}\n.logobar-item:hover .logobar-name{\n  opacity:1;\n}\n.logobar-subtitle{\n  font-family:\'Noto Sans\',sans-serif;\n  font-size:16px;\n  font-weight:400;\n  color:#5b6b80;\n  text-transform:uppercase;\n  letter-spacing:0.06em;\n  line-height:1.25;\n  margin-top:4px;\n}\n\n/* ===== STATS ROW ===== */\n.logobar-stats{\n  display:flex;\n  gap:60px;\n  justify-content:center;\n  align-items:center;\n  padding:32px 40px 0;\n  border-top:1px solid #e2e8f0;\n  max-width:1200px;\n  margin:0 auto;\n}\n.logobar-stat{\n  display:block;\n  text-align:center;\n}\n.logobar-stat-value{\n  font-family:\'Noto Sans\',sans-serif;\n  font-size:28px;\n  font-weight:700;\n  color:#000864;\n  line-height:1.2;\n  letter-spacing:normal;\n}\n.logobar-stat-label{\n  font-family:\'Noto Sans\',sans-serif;\n  font-size:13px;\n  color:#5b6b80;\n  text-align:center;\n  line-height:1.6;\n  margin-top:4px;\n}\n\n/* ===== RESPONSIVE ===== */\n@media(max-width:1024px){\n  .logobar-marquee{gap:48px}\n  .logobar-logo{height:80px;max-width:96px}\n  .logobar-placeholder{width:80px;height:80px;font-size:24px}\n  .logobar-name{font-size:24px}\n  .logobar-subtitle{font-size:13px}\n  .logobar-stats{gap:40px}\n}\n@media(max-width:768px){\n  .logobar-marquee{gap:40px}\n  .logobar-logo{height:64px;max-width:76px}\n  .logobar-placeholder{width:64px;height:64px;font-size:20px}\n  .logobar-name{font-size:20px}\n  .logobar-subtitle{font-size:11px}\n  .logobar-stats{flex-direction:column;gap:24px;padding-top:24px}\n  .logobar-stat-value{font-size:24px}\n  .logobar-stat-label{font-size:12px}\n}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row{padding:0 24px !important}\n  .logobar-marquee-wrapper{padding:40px 0}\n  .logobar-marquee{gap:36px}\n  .logobar-logo{height:52px;max-width:60px}\n  .logobar-placeholder{width:52px;height:52px;font-size:16px;border-radius:8px}\n  .logobar-item{gap:16px}\n  .logobar-name{font-size:16px}\n  .logobar-subtitle{display:none}\n  .logobar-stat-value{font-size:20px}\n  .logobar-stat-label{font-size:11px}\n}\n\n/* ===== REDUCED MOTION ===== */\n@media(prefers-reduced-motion:reduce){\n  .logobar-marquee{\n    animation:none;\n    flex-wrap:wrap;\n    justify-content:center;\n    width:100%;\n  }\n  .logobar-item[aria-hidden="true"]{\n    display:none;\n  }\n  .logobar-marquee-wrapper{\n    mask-image:none;\n    -webkit-mask-image:none;\n  }\n}\n/* Super D decoration */\n.fchecks-deco{position:absolute;top:50%;right:auto;left:-15%;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center left;background-size:contain;transform:translateY(-50%);opacity:0.1;pointer-events:none;z-index:0}\n/* === FACTORY CHECKS — 5 PAIN POINTS === */\n.checks-section{position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px;background:linear-gradient(165deg, #f8fafc 0%, #f1f5f9 100%);padding:100px 40px}\n\n/* Scene SVG */\n.checks-scene{position:absolute;inset:0;pointer-events:none;z-index:1;opacity:0.2}\n.checks-scene svg{width:100%;height:100%}\n\n/* Section Header */\n\n.checks-header{text-align:center;max-width:1200px;margin:0 auto 64px;position:relative;z-index:2}\n.checks-header-label{font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.2em;color:#0369a1;margin-bottom:16px;line-height:1.6;display:flex;align-items:center;justify-content:center;gap:12px}\n.checks-header-label::before,.checks-header-label::after{content:\'\';width:40px;height:1px;background:linear-gradient(90deg,transparent,#00AFF0);flex-shrink:0}\n.checks-header-label::after{transform:scaleX(-1)}\n.checks-title{font-family:\'Noto Sans\',sans-serif;font-size:clamp(32px,3.5vw,44px);font-weight:700;color:#000864;line-height:1.6;letter-spacing:-0.02em;margin:0 0 16px;padding:0}\n.checks-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;max-width:600px;margin:0 auto;padding:0}\n\n/* Cards Grid */\n.checks-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:32px;margin-bottom:32px;max-width:1200px;margin-left:auto;margin-right:auto;position:relative;z-index:2}\n\n/* Cards */\n.checks-card{background:#fff;border:1px solid #e2e8f0;border-radius:20px;padding:40px 32px;transition:all 0.2s ease;position:relative;overflow:hidden;line-height:1.6;box-shadow:0 4px 24px rgba(0,0,0,0.04)}\n.checks-card:hover{box-shadow:0 20px 60px rgba(0,175,240,0.12);border-color:#00AFF0}\n.checks-card--full{grid-column:1 / -1}\n.checks-card>*:not(.checks-card-bg):not(.checks-bg-icon){position:relative;z-index:1}\n\n/* Card Elements */\n.checks-card-number{font-family:\'Noto Sans\',sans-serif;font-size:64px;font-weight:800;line-height:1;color:#0369a1;opacity:0.15;margin-bottom:24px}\n.checks-card-title{font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:700;line-height:1.6;color:#000864;margin:0 0 16px;position:relative;z-index:1}\n.checks-card-quote{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:400;font-style:italic;line-height:1.7;color:#475569;margin:0 0 20px;padding-left:16px;border-left:3px solid #00AFF0}\n.checks-card-desc{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:400;line-height:1.6;color:#5b6b80;margin:0}\n\n/* Card Background SVGs */\n.checks-card-bg{position:absolute;top:0;right:0;width:220px;height:100%;opacity:0.10;pointer-events:none;z-index:0;transition:opacity 0.4s ease}\n.checks-card:hover .checks-card-bg{opacity:0.14}\n.checks-card--full .checks-card-bg{width:400px}\n\n\n\n\n\n\n\n\n\n\n\n\n\n/* CTA */\n\n.checks-cta-wrapper{text-align:center;margin-top:56px;position:relative;z-index:2}\n.checks-cta{display:inline-flex;align-items:center;gap:8px;font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;line-height:1.6;color:#ffffff;background:#006dac;padding:16px 32px;border-radius:8px;text-decoration:none;transition:all 0.3s ease;box-shadow:0 4px 14px rgba(0,175,240,0.35)}\n.checks-cta::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.checks-cta:hover::before{left:100%}\n.checks-cta:hover{background:#003CC8;transform:translateY(-2px);box-shadow:0 6px 20px rgba(0,175,240,0.45)}\n\n/* Responsive */\n@media(max-width:1024px){\n  .checks-grid{grid-template-columns:repeat(2,1fr)}\n  .checks-title{font-size:40px}\n  .checks-subtitle{font-size:18px}\n  .checks-grid .checks-card:nth-child(3){grid-column:span 2;max-width:500px;margin:0 auto;width:100%}\n}\n@media(max-width:768px){\n  .checks-section{padding:80px 24px !important}\n  .checks-header{margin-bottom:60px}\n  .checks-grid{grid-template-columns:1fr;gap:24px}\n  .checks-grid .checks-card:nth-child(3){grid-column:auto;max-width:none}\n  .checks-title{font-size:32px}\n  .checks-subtitle{font-size:16px}\n  .checks-card{padding:32px 24px}\n  .checks-card-number{font-size:52px}\n  .checks-card-title{font-size:20px}\n  .checks-card-quote{font-size:15px}\n  .checks-card-desc{font-size:14px}\n  \n  \n  .checks-label-line{width:30px}\n  .checks-label-text{font-size:12px}\n  .checks-header-label{font-size:10px}\n}\n@media(max-width:480px){\n  .checks-section{padding:60px 20px !important}\n  .checks-header{margin-bottom:48px}\n  .checks-title{font-size:28px}\n  .checks-btn{width:100%;text-align:center}\n  .checks-header-label::before,.checks-header-label::after{width:24px}\n}\n\n/* Reduced Motion */\n@media(prefers-reduced-motion:reduce){\n  .checks-card,.checks-cta,.checks-btn{transition:none !important}\n  .checks-card:hover,.checks-cta:hover,.checks-btn:hover{transform:none !important}\n  \n  .checks-btn::before{transition:none}\n}\n/* === PARTNER UNDERSTANDING CHECKS === */\n.pchecks-section{position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px;background:linear-gradient(165deg, #0f1419 0%, #1a2632 50%, #000864 100%);padding:100px 40px}\n\n/* Scene SVG */\n.pchecks-scene{position:absolute;inset:0;po