harray="4 3"/>\n    <path d="M680 350 L740 330" stroke="#000864" stroke-width="1" opacity="0.2"/>\n    <circle cx="220" cy="340" r="4" fill="#000864" opacity="0.35"/><circle cx="290" cy="410" r="3" fill="#000864" opacity="0.25"/>\n    <circle cx="640" cy="280" r="5" fill="#00AFF0" opacity="0.25"/><circle cx="850" cy="640" r="3" fill="#000864" opacity="0.3"/>\n    <circle cx="1060" cy="330" r="4" fill="#000864" opacity="0.25"/><circle cx="1300" cy="440" r="3" fill="#00AFF0" opacity="0.2"/>\n    <circle cx="520" cy="760" r="4" fill="#000864" opacity="0.25"/><circle cx="160" cy="630" r="3" fill="#000864" opacity="0.3"/>\n    <circle cx="1150" cy="760" r="5" fill="#000864" opacity="0.2"/><circle cx="80" cy="450" r="3" fill="#000864" opacity="0.2"/>\n    <text x="560" y="300" font-family="\'Noto Sans\',sans-serif" font-size="36" font-weight="800" fill="#000864" opacity="0.12">?</text>\n    <text x="1070" y="600" font-family="\'Noto Sans\',sans-serif" font-size="28" font-weight="800" fill="#000864" opacity="0.10">?</text>\n    <text x="200" y="560" font-family="\'Noto Sans\',sans-serif" font-size="22" font-weight="800" fill="#000864" opacity="0.08">?</text>\n    <rect x="620" y="600" width="35" height="25" rx="2" stroke="#000864" stroke-width="1" opacity="0.2"/>\n    <line x1="625" y1="608" x2="650" y2="608" stroke="#000864" stroke-width="0.5" opacity="0.2"/>\n    <line x1="625" y1="614" x2="645" y2="614" stroke="#000864" stroke-width="0.5" opacity="0.2"/>\n    <line x1="625" y1="620" x2="648" y2="620" stroke="#000864" stroke-width="0.5" opacity="0.2"/>\n    <rect x="1050" y="150" width="30" height="20" rx="2" stroke="#000864" stroke-width="1" opacity="0.2"/>\n    <line x1="1055" y1="157" x2="1075" y2="157" stroke="#000864" stroke-width="0.5" opacity="0.2"/>\n    <line x1="1055" y1="163" x2="1070" y2="163" stroke="#000864" stroke-width="0.5" opacity="0.2"/>\n  </svg></div>\n    \n    <div class="checks-header">\n      <div class="checks-header-label">For Manufacturing Business Owners</div>\n      <h2 class="checks-title">Do You Recognize These Problems?</h2>\n      <p class="checks-subtitle">If any of these sound familiar, you’re not alone. These are the most common problems we solve for factories across Thailand and Asia.</p>\n    </div>\n    <div class="checks-grid">\n    <div class="checks-card">\n      \n      <svg aria-hidden="true" class="checks-card-bg" viewBox="-40 0 280 320" fill="none" preserveAspectRatio="xMaxYMid slice"><rect x="40" y="20" width="60" height="18" rx="2" stroke="#000864" stroke-width="1.5" fill="none"/><rect x="110" y="20" width="80" height="18" rx="2" stroke="#000864" stroke-width="1.5" fill="none"/><rect x="20" y="48" width="80" height="18" rx="2" stroke="#000864" stroke-width="1.5" fill="none"/><rect x="110" y="48" width="60" height="18" rx="2" stroke="#000864" stroke-width="1.5" fill="none"/><rect x="60" y="76" width="90" height="18" rx="2" stroke="#000864" stroke-width="1.5" fill="none"/><rect x="30" y="104" width="50" height="18" rx="2" stroke="#000864" stroke-width="1.5" fill="none"/><rect x="90" y="104" width="100" height="18" rx="2" stroke="#000864" stroke-width="1.5" fill="none"/><rect x="50" y="132" width="70" height="18" rx="2" stroke="#000864" stroke-width="1.5" fill="none"/><rect x="130" y="132" width="60" height="18" rx="2" stroke="#000864" stroke-width="1.5" fill="none"/><line x1="70" y1="40" x2="55" y2="48" stroke="#00AFF0" stroke-width="1" stroke-dasharray="3 3"/><line x1="140" y1="40" x2="120" y2="48" stroke="#00AFF0" stroke-width="1" stroke-dasharray="3 3"/><line x1="100" y1="96" x2="65" y2="104" stroke="#00AFF0" stroke-width="1" stroke-dasharray="3 3"/><circle cx="180" cy="80" r="3" fill="#000864"/><circle cx="25" cy="90" r="2" fill="#000864"/><circle cx="195" cy="150" r="4" fill="#000864"/><circle cx="15" cy="160" r="2.5" fill="#000864"/><text x="160" y="220" font-family="\'Noto Sans\'" font-size="80" font-weight="800" fill="#000864" opacity="0.4">?</text></svg>\n      \n      \n      <div class="checks-card-number">01</div>\n      <h3 class="checks-card-title">“Shadow Excel” Reality</h3>\n      <div class="checks-card-quote">“You know your factory isn’t actually running on your current system—it’s running on spreadsheets because your staff finds the software too rigid or slow.”</div>\n      \n      <p class="checks-card-desc">Your real operations live in unconnected Excel files, not in your ERP. Financial data doesn’t match physical reality because planners work outside the system.</p>\n      \n    </div>\n    <div class="checks-card">\n      \n      <svg aria-hidden="true" class="checks-card-bg" viewBox="0 0 220 320" fill="none" preserveAspectRatio="xMaxYMid slice"><path d="M70 80 L150 60 L200 100 L200 220 L120 240 L70 200Z" fill="#000864" opacity="0.15"/><path d="M70 80 L150 60 L200 100 L120 120 L70 80Z" fill="#000864" opacity="0.25"/><path d="M120 120 L200 100 L200 220 L120 240Z" fill="#000864" opacity="0.2"/><path d="M70 80 L120 120 L120 240 L70 200Z" fill="#000864" opacity="0.1"/><rect x="82" y="145" width="26" height="22" rx="3" stroke="#000864" stroke-width="2" fill="none" opacity="0.5"/><path d="M88 145 L88 135 Q88 125 95 125 Q102 125 102 135 L102 145" stroke="#000864" stroke-width="2" fill="none" opacity="0.5"/><circle cx="95" cy="157" r="3" fill="#000864" opacity="0.5"/><path d="M30 100 L60 100" stroke="#00AFF0" stroke-width="1.5"/><path d="M130 260 L160 260" stroke="#00AFF0" stroke-width="1.5"/><text x="15" y="95" font-family="\'Noto Sans\'" font-size="10" fill="#000864" opacity="0.5">IN</text><text x="165" y="255" font-family="\'Noto Sans\'" font-size="10" fill="#000864" opacity="0.5">OUT</text><text x="85" y="290" font-family="\'Noto Sans\'" font-size="12" fill="#000864" opacity="0.3" font-weight="700">3 WEEKS?</text></svg>\n      \n      \n      <div class="checks-card-number">02</div>\n      <h3 class="checks-card-title">“The Black Box” Problem</h3>\n      <div class="checks-card-quote">“You know exactly how much raw material you bought and how many finished goods you sold, but the 3 weeks in between — your work in progress — are invisible.”</div>\n      \n      <p class="checks-card-desc">You rely on paper reports filled out yesterday to understand what happened today. You can’t see what’s happening on the floor right now without walking over and asking.</p>\n      \n    </div>\n    <div class="checks-card">\n      \n      <svg aria-hidden="true" class="checks-card-bg" viewBox="0 0 220 320" fill="none" preserveAspectRatio="xMaxYMid slice"><line x1="40" y1="60" x2="200" y2="60" stroke="#000864" stroke-width="2"/><line x1="40" y1="120" x2="200" y2="120" stroke="#000864" stroke-width="2"/><line x1="40" y1="180" x2="200" y2="180" stroke="#000864" stroke-width="2"/><line x1="50" y1="55" x2="50" y2="185" stroke="#000864" stroke-width="1.5"/><line x1="190" y1="55" x2="190" y2="185" stroke="#000864" stroke-width="1.5"/><rect x="60" y="40" width="25" height="18" rx="2" fill="#000864" opacity="0.3"/><rect x="95" y="40" width="25" height="18" rx="2" stroke="#000864" stroke-width="1" fill="none" stroke-dasharray="3 2" opacity="0.5"/><rect x="130" y="40" width="25" height="18" rx="2" stroke="#000864" stroke-width="1" fill="none" stroke-dasharray="3 2" opacity="0.5"/><rect x="165" y="40" width="20" height="18" rx="2" fill="#000864" opacity="0.3"/><rect x="60" y="100" width="25" height="18" rx="2" fill="#000864" opacity="0.3"/><rect x="95" y="100" width="25" height="18" rx="2" fill="#000864" opacity="0.3"/><rect x="130" y="100" width="25" height="18" rx="2" stroke="#000864" stroke-width="1" fill="none" stroke-dasharray="3 2" opacity="0.5"/><rect x="60" y="160" width="25" height="18" rx="2" stroke="#000864" stroke-width="1" fill="none" stroke-dasharray="3 2" opacity="0.5"/><text x="60" y="220" font-family="\'Noto Sans\'" font-size="14" fill="#000864" opacity="0.4" font-weight="700">System: 100</text><text x="60" y="245" font-family="\'Noto Sans\'" font-size="14" fill="#00AFF0" opacity="0.6" font-weight="700">Reality: 50</text><text x="150" y="232" font-family="\'Noto Sans\'" font-size="36" fill="#000864" opacity="0.3" font-weight="800">≠</text></svg>\n      \n      \n      <div class="checks-card-number">03</div>\n      <h3 class="checks-card-title">“Ghost Inventory” Crisis</h3>\n      <div class="checks-card-quote">“The system says you have 100 units, but the shelf has 50. This discrepancy forces your team to hoard ‘safety stock’ just to survive.”</div>\n      \n      <p class="checks-card-desc">Inventory inaccuracy ties up millions in unnecessary capital and destroys your ability to promise reliable delivery dates. The “borrowing culture” has replaced discipline.</p>\n      \n    </div>\n    <div class="checks-card checks-card--full">\n      \n      <svg aria-hidden="true" class="checks-card-bg" viewBox="0 0 400 180" fill="none" preserveAspectRatio="xMaxYMid slice"><path d="M280 150 L280 60" stroke="#000864" stroke-width="2" opacity="0.3"/><path d="M275 70 L280 55 L285 70" stroke="#000864" stroke-width="2" fill="none" opacity="0.3"/><path d="M320 140 L320 40" stroke="#000864" stroke-width="2" opacity="0.4"/><path d="M315 50 L320 35 L325 50" stroke="#000864" stroke-width="2" fill="none" opacity="0.4"/><path d="M360 130 L360 25" stroke="#00AFF0" stroke-width="2.5" opacity="0.3"/><path d="M355 35 L360 18 L365 35" stroke="#00AFF0" stroke-width="2.5" fill="none" opacity="0.3"/><rect x="230" y="70" width="40" height="24" rx="4" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.3"/><text x="237" y="87" font-family="\'Noto Sans\'" font-size="11" fill="#000864" opacity="0.4">$???</text><rect x="230" y="110" width="40" height="24" rx="4" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.3"/><text x="234" y="127" font-family="\'Noto Sans\'" font-size="11" fill="#000864" opacity="0.4">+15%</text><text x="100" y="140" font-family="\'Noto Sans\'" font-size="72" font-weight="800" fill="#000864" opacity="0.06">15%</text></svg>\n      \n      \n      <div class="checks-card-number">04</div>\n      <h3 class="checks-card-title">“Cost Guesswork” Trap</h3>\n      <div class="checks-card-quote">“You quoted a price last month based on estimated costs. This month the same product costs 15% more to make — and you have no idea why.”</div>\n      \n      <p class="checks-card-desc">Batch-to-batch cost fluctuations are invisible without production-order-level tracking. You’re pricing based on last quarter’s averages, not this morning’s reality.</p>\n      \n    </div>\n    <div class="checks-card checks-card--full">\n      \n      <svg aria-hidden="true" class="checks-card-bg" viewBox="0 0 400 180" fill="none" preserveAspectRatio="xMaxYMid slice"><circle cx="310" cy="90" r="60" stroke="#000864" stroke-width="2" fill="none" opacity="0.2"/><circle cx="310" cy="90" r="3" fill="#000864" opacity="0.3"/><line x1="310" y1="90" x2="310" y2="50" stroke="#000864" stroke-width="2.5" opacity="0.3" stroke-linecap="round"/><line x1="310" y1="90" x2="345" y2="100" stroke="#000864" stroke-width="2" opacity="0.25" stroke-linecap="round"/><line x1="310" y1="32" x2="310" y2="38" stroke="#000864" stroke-width="1.5" opacity="0.3"/><line x1="310" y1="142" x2="310" y2="148" stroke="#000864" stroke-width="1.5" opacity="0.3"/><line x1="252" y1="90" x2="258" y2="90" stroke="#000864" stroke-width="1.5" opacity="0.3"/><line x1="362" y1="90" x2="368" y2="90" stroke="#000864" stroke-width="1.5" opacity="0.3"/><text x="275" y="170" font-family="\'Noto Sans\'" font-size="14" fill="#000864" opacity="0.3" font-weight="700">20 min...</text><rect x="200" y="50" width="30" height="50" rx="6" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.2"/><line x1="208" y1="88" x2="222" y2="88" stroke="#000864" stroke-width="1" opacity="0.2"/><path d="M235 65 Q242 65 242 72" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.3"/><path d="M235 60 Q248 60 248 75" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.25"/><path d="M235 55 Q254 55 254 78" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.2"/></svg>\n      \n      \n      <div class="checks-card-number">05</div>\n      <h3 class="checks-card-title">“10-Second Answer” Failure</h3>\n      <div class="checks-card-quote">“When your biggest customer calls and asks ‘where is my order?’ — you put them on hold, walk to the shop floor, and hope someone knows.”</div>\n      \n      <p class="checks-card-desc">Real-time delivery status should be a click away, not a 20-minute investigation. Every hold costs you credibility with the customers who matter most.</p>\n      \n    </div></div>\n    <div class="checks-cta-wrapper"><a href="/demo/" class="checks-cta">Let’s Talk About Your Factory</a></div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Partner Understanding Checks"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Partner Understanding Checks: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Partner Understanding Checks: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pchecks-section">\n    <div class="pchecks-scene"><svg aria-hidden="true" viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice">\n    <rect x="150" y="550" width="50" height="250" rx="3" stroke="#ffffff" stroke-width="1.5" fill="none" opacity="0.15"/>\n    <rect x="240" y="450" width="50" height="350" rx="3" stroke="#ffffff" stroke-width="1.5" fill="none" opacity="0.18"/>\n    <rect x="330" y="370" width="50" height="430" rx="3" stroke="#ffffff" stroke-width="1.5" fill="none" opacity="0.2"/>\n    <rect x="420" y="320" width="50" height="480" rx="3" stroke="#ffffff" stroke-width="1.5" fill="none" opacity="0.22"/>\n    <rect x="510" y="300" width="50" height="500" rx="3" stroke="#ffffff" stroke-width="1.5" fill="none" opacity="0.22"/>\n    <rect x="600" y="290" width="50" height="510" rx="3" stroke="#ffffff" stroke-width="1.5" fill="none" opacity="0.2"/>\n    <rect x="690" y="285" width="50" height="515" rx="3" stroke="#ffffff" stroke-width="1.5" fill="none" opacity="0.18"/>\n    <line x1="100" y1="270" x2="800" y2="270" stroke="#00AFF0" stroke-width="2.5" stroke-dasharray="12 8" opacity="0.3"/>\n    <text x="810" y="278" font-family="\'Noto Sans\',sans-serif" font-size="16" font-weight="700" fill="#ffffff" opacity="0.1">CAP</text>\n    <circle cx="1050" cy="350" r="90" stroke="#ffffff" stroke-width="2" fill="none" opacity="0.12"/>\n    <line x1="1050" y1="350" x2="1050" y2="280" stroke="#ffffff" stroke-width="2.5" opacity="0.15" stroke-linecap="round"/>\n    <line x1="1050" y1="350" x2="1100" y2="370" stroke="#ffffff" stroke-width="2" opacity="0.12" stroke-linecap="round"/>\n    <circle cx="1050" cy="350" r="4" fill="#ffffff" opacity="0.2"/>\n    <line x1="1050" y1="262" x2="1050" y2="270" stroke="#ffffff" stroke-width="1.5" opacity="0.15"/>\n    <line x1="1050" y1="430" x2="1050" y2="438" stroke="#ffffff" stroke-width="1.5" opacity="0.15"/>\n    <line x1="962" y1="350" x2="970" y2="350" stroke="#ffffff" stroke-width="1.5" opacity="0.15"/>\n    <line x1="1130" y1="350" x2="1138" y2="350" stroke="#ffffff" stroke-width="1.5" opacity="0.15"/>\n    <text x="900" y="580" font-family="\'Noto Sans\',sans-serif" font-size="20" font-weight="800" fill="#ffffff" opacity="0.05">HEADCOUNT = REVENUE</text>\n    <line x1="1250" y1="200" x2="1250" y2="700" stroke="#ffffff" stroke-width="1" opacity="0.08"/>\n    <line x1="1300" y1="280" x2="1300" y2="620" stroke="#ffffff" stroke-width="1" opacity="0.08"/>\n    <line x1="1350" y1="350" x2="1350" y2="550" stroke="#ffffff" stroke-width="1" opacity="0.08"/>\n    <path d="M1240 400 L1250 390 L1260 400" stroke="#00AFF0" stroke-width="1.5" fill="none" opacity="0.2"/>\n    <path d="M1240 500 L1250 510 L1260 500" stroke="#00AFF0" stroke-width="1.5" fill="none" opacity="0.2"/>\n    <circle cx="180" cy="300" r="3" fill="#ffffff" opacity="0.1"/><circle cx="500" cy="200" r="4" fill="#ffffff" opacity="0.08"/>\n    <circle cx="750" cy="400" r="3" fill="#00AFF0" opacity="0.15"/><circle cx="1200" cy="650" r="3.5" fill="#ffffff" opacity="0.08"/>\n  </svg></div>\n    \n    <div class="pchecks-header">\n      <div class="pchecks-label">\n        <span class="pchecks-label-line"></span>\n        <span class="pchecks-label-text">For ERP Implementers</span>\n        <span class="pchecks-label-line"></span>\n      </div>\n      <h2 class="pchecks-title">Trapped in These Cycles?</h2>\n      <p class="pchecks-subtitle">The consulting model has structural limits. Recognizing these traps is the first step to escaping them.</p>\n    </div>\n    <div class="pchecks-grid">\n    <div class="pchecks-card">\n      \n      \n      \n      \n      <div class="pchecks-card-number">01</div>\n      <h3 class="pchecks-card-title">“The Man-Day Trap”</h3>\n      <blockquote class="pchecks-card-quote">“Your revenue is mathematically capped by your headcount. You cannot grow your top line without proportionally increasing your payroll costs.”</blockquote>\n      \n      <p class="pchecks-card-desc">You are selling hours, not assets. Revenue = Hours Worked, making exponential growth impossible. Every January, you start at zero again.</p>\n      \n    </div>\n    <div class="pchecks-card">\n      \n      \n      \n      \n      <div class="pchecks-card-number">02</div>\n      <h3 class="pchecks-card-title">“Customization Death Spiral”</h3>\n      <blockquote class="pchecks-card-quote">“You accept customization requests to win the deal, but then you become married to that code forever.”</blockquote>\n      \n      <p class="pchecks-card-desc">You can’t upgrade clients on custom code. Support becomes a nightmare of unbillable hours. Your profit evaporated the moment you said “Yes” to a non-standard request.</p>\n      \n    </div>\n    <div class="pchecks-card">\n      \n      \n      \n      \n      <div class="pchecks-card-number">03</div>\n      <h3 class="pchecks-card-title">“The Ghost IT Burden”</h3>\n      <blockquote class="pchecks-card-quote">“You aren’t just their ERP consultant—you are their unpaid IT department, fixing Wi-Fi, printers, and user discipline issues.”</blockquote>\n      \n      <p class="pchecks-card-desc">Most Thai SMEs lack a dedicated IT manager. You end up subsidizing their operations with your margins — absorbing unbillable work you feel forced to do just to keep the relationship alive.</p>\n      \n    </div></div>\n    <div class="pchecks-cta-wrapper"><a href="/partner-program/" class="pchecks-cta">See the Way Out</a></div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Home: Product Pillars"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Home: Product Pillars: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Home: Product Pillars: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="products-section">\n    <div class="products-deco" aria-hidden="true"></div>\n    \n    <div class="products-header">\n      <div class="products-header-label">Complete Manufacturing Stack</div>\n      <h2 class="products-title">One Ecosystem. Total Visibility.</h2>\n      <p class="products-subtitle">From financials to the factory floor, every DigiWin product works together—no integration nightmares, no data silos.</p>\n    </div>\n    <div class="products-grid">\n    <a href="/products/erp/" class="products-card">\n      \n      <div class="products-card__icon"><svg width="36" height="36" viewBox="0 0 36 36" fill="none" xmlns="http://www.w3.org/2000/svg"><rect x="4" y="3" width="16" height="22" rx="2" fill="#00AFF0" fill-opacity="0.15" stroke="#00AFF0" stroke-width="2"/><path d="M8 9h8M8 13h6M8 17h7" stroke="#00AFF0" stroke-width="2" stroke-linecap="round"/><rect x="16" y="14" width="14" height="18" rx="2" fill="#000864" stroke="#00AFF0" stroke-width="2"/><rect x="19" y="17" width="8" height="4" rx="1" fill="#00AFF0" fill-opacity="0.3"/><circle cx="21" cy="26" r="1.5" fill="#00AFF0"/><circle cx="26" cy="26" r="1.5" fill="#00AFF0"/><circle cx="21" cy="29" r="1.5" fill="#00AFF0"/><circle cx="26" cy="29" r="1.5" fill="#00AFF0"/><circle cx="28" cy="7" r="5" fill="#000864" stroke="#00AFF0" stroke-width="2"/><text x="28" y="10" text-anchor="middle" fill="#00AFF0" font-size="8" font-weight="bold">$</text></svg></div>\n      <h3 class="products-card__title">ERP Core</h3>\n      \n      <div class="products-card__full-name">Enterprise Resource Planning</div>\n      \n      <div class="products-card__tagline">The central brain of your business</div>\n      \n      <ul class="products-card__features">\n        <li><strong>Financials</strong> — accounting, invoicing, budgets in one place</li>\n        <li><strong>Inventory</strong> — real-time stock levels across locations</li>\n        <li><strong>Operations</strong> — purchase orders, sales, and costs connected</li>\n      </ul>\n      \n      <div class="products-card__benefit">Replace scattered spreadsheets with one source of truth.</div>\n      \n    </a>\n    <a href="/products/mes/" class="products-card">\n      \n      <div class="products-card__icon"><svg width="36" height="36" viewBox="0 0 36 36" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M3 28V12l8-6v8l8-6v8l8-6v12" fill="#00AFF0" fill-opacity="0.15" stroke="#00AFF0" stroke-width="2" stroke-linejoin="round"/><rect x="6" y="16" width="4" height="4" rx="0.5" fill="#00AFF0"/><rect x="14" y="16" width="4" height="4" rx="0.5" fill="#00AFF0"/><rect x="22" y="16" width="4" height="4" rx="0.5" fill="#00AFF0"/><rect x="3" y="28" width="30" height="4" rx="1" fill="#000864" stroke="#00AFF0" stroke-width="2"/><rect x="8" y="25" width="5" height="4" rx="1" fill="#00AFF0"/><rect x="18" y="25" width="5" height="4" rx="1" fill="#00AFF0" fill-opacity="0.6"/><circle cx="8" cy="30" r="1.5" fill="#00AFF0"/><circle cx="18" cy="30" r="1.5" fill="#00AFF0"/><circle cx="28" cy="30" r="1.5" fill="#00AFF0"/></svg></div>\n      <h3 class="products-card__title">MES</h3>\n      \n      <div class="products-card__full-name">Manufacturing Execution System</div>\n      \n      <div class="products-card__tagline">Your digital eyes on the production floor</div>\n      \n      <ul class="products-card__features">\n        <li><strong>Track</strong> — follow every product through each workstation</li>\n        <li><strong>Record</strong> — who made what, when, and how</li>\n        <li><strong>Alert</strong> — spot delays and quality issues instantly</li>\n      </ul>\n      \n      <div class="products-card__benefit">Answer “which batch was my order?” in seconds.</div>\n      \n    </a>\n    <a href="/products/wms/" class="products-card">\n      \n      <div class="products-card__icon"><svg width="36" height="36" viewBox="0 0 36 36" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M4 32V4M14 32V4M24 32V4M34 32V4" stroke="#00AFF0" stroke-width="2"/><path d="M4 12h30M4 22h30M4 32h30" stroke="#00AFF0" stroke-width="2"/><rect x="6" y="6" width="6" height="5" rx="1" fill="#00AFF0"/><rect x="16" y="7" width="6" height="4" rx="1" fill="#00AFF0" fill-opacity="0.7"/><rect x="26" y="6" width="6" height="5" rx="1" fill="#00AFF0" fill-opacity="0.5"/><rect x="6" y="15" width="6" height="6" rx="1" fill="#00AFF0" fill-opacity="0.6"/><rect x="16" y="14" width="6" height="7" rx="1" fill="#00AFF0"/><rect x="26" y="16" width="6" height="5" rx="1" fill="#00AFF0" fill-opacity="0.8"/><rect x="6" y="25" width="6" height="6" rx="1" fill="#00AFF0" fill-opacity="0.5"/><rect x="17" y="24" width="5" height="7" rx="1" fill="#00AFF0" fill-opacity="0.7"/><rect x="26" y="25" width="6" height="6" rx="1" fill="#00AFF0"/></svg></div>\n      <h3 class="products-card__title">WMS</h3>\n      \n      <div class="products-card__full-name">Warehouse Management System</div>\n      \n      <div class="products-card__tagline">Never lose track of inventory again</div>\n      \n      <ul class="products-card__features">\n        <li><strong>Locate</strong> — know which shelf, bin, and zone for every item</li>\n        <li><strong>Guide</strong> — barcode scanning for pick, pack, and ship</li>\n        <li><strong>Count</strong> — cycle counts that match reality</li>\n      </ul>\n      \n      <div class="products-card__benefit">Faster fulfillment, fewer mistakes, accurate stock.</div>\n      \n    </a>\n    <a href="/products/aiot/" class="products-card">\n      \n      <div class="products-card__icon"><svg width="36" height="36" viewBox="0 0 36 36" fill="none" xmlns="http://www.w3.org/2000/svg"><rect x="12" y="12" width="12" height="12" rx="2" fill="#000864" stroke="#00AFF0" stroke-width="2"/><text x="18" y="20" text-anchor="middle" fill="#00AFF0" font-size="6" font-weight="bold">AI</text><path d="M12 18H6M24 18h6M18 12V6M18 24v6" stroke="#00AFF0" stroke-width="2"/><path d="M13 13L8 8M23 13l5-5M13 23l-5 5M23 23l5 5" stroke="#00AFF0" stroke-width="1.5" stroke-dasharray="3 2"/><circle cx="5" cy="18" r="3" fill="#00AFF0"/><circle cx="31" cy="18" r="3" fill="#00AFF0"/><circle cx="18" cy="5" r="3" fill="#00AFF0"/><circle cx="18" cy="31" r="3" fill="#00AFF0"/><circle cx="6" cy="6" r="2.5" fill="#00AFF0" fill-opacity="0.6"/><circle cx="30" cy="6" r="2.5" fill="#00AFF0" fill-opacity="0.6"/><circle cx="6" cy="30" r="2.5" fill="#00AFF0" fill-opacity="0.6"/><circle cx="30" cy="30" r="2.5" fill="#00AFF0" fill-opacity="0.6"/></svg></div>\n      <h3 class="products-card__title">AIoT</h3>\n      \n      <div class="products-card__full-name">AI + Internet of Things</div>\n      \n      <div class="products-card__tagline">Connect your machines to the digital world</div>\n      \n      <ul class="products-card__features">\n        <li><strong>Collect</strong> — temperature, speed, vibration automatically</li>\n        <li><strong>Predict</strong> — machine breakdowns before they happen</li>\n        <li><strong>Optimize</strong> — energy usage and efficiency gains</li>\n      </ul>\n      \n      <div class="products-card__benefit">No manual logging. AI finds what humans miss.</div>\n      \n    </a></div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Industry Tabs"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Column"}}},"decoration":{}}} -->\n<!-- wp:divi/code {"content":{"innerContent":{"desktop":{"value":"\\n    <div class=\\"ind-section\\">\\n    <div class=\\"ind-container\\">\\n      <div class=\\"ind-header\\">\\n        <div class=\\"ind-label\\">Industry Expertise</div>\\n        <h2 class=\\"ind-title\\">Built for Your Industry</h2>\\n        <p class=\\"ind-subtitle\\">We don’t just understand manufacturing—we understand YOUR manufacturing.</p>\\n      </div>\\n\\n      <div class=\\"ind-content-wrapper-outer\\">\\n      <div class=\\"ind-tab-bar\\">\\n        <button class=\\"ind-tab ind-tab-active\\" data-tab=\\"automotive\\" onclick=\\"dwSwitchTab_ind(\'automotive\')\\">Automotive Parts</button>\\n        <button class=\\"ind-tab\\" data-tab=\\"electronics\\" onclick=\\"dwSwitchTab_ind(\'electronics\')\\">Electronics Assembly</button>\\n        <button class=\\"ind-tab\\" data-tab=\\"metal-plastics\\" onclick=\\"dwSwitchTab_ind(\'metal-plastics\')\\">Metal & Plastics</button>\\n      </div>\\n\\n      <div class=\\"ind-content-wrapper\\">\\n        \\n        <div class=\\"ind-tab-content ind-tab-active\\" id=\\"ind-tab-automotive\\">\\n          <div class=\\"ind-grid\\">\\n            <div class=\\"ind-image-container\\" id=\\"ind-svg-automotive\\"></div>\\n            <div class=\\"ind-text-content\\">\\n              <h3 class=\\"ind-content-title\\">Automotive Parts Manufacturing</h3>\\n              <p class=\\"ind-content-desc\\">Thailand is ASEAN’s automotive hub. We understand what tier-1 OEMs (Original Equipment Manufacturers) demand: perfect traceability, just-in-time delivery, and EDI (Electronic Data Interchange) integration that works — every time.</p>\\n              <ul class=\\"ind-features\\">\\n                <li><svg width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 20 20\\" fill=\\"none\\" xmlns=\\"http://www.w3.org/2000/svg\\"><defs><linearGradient id=\\"ind-check-automotive-0\\" x1=\\"0%\\" y1=\\"0%\\" x2=\\"100%\\" y2=\\"100%\\"><stop offset=\\"0%\\" style=\\"stop-color:#00AFF0;stop-opacity:1\\"/><stop offset=\\"100%\\" style=\\"stop-color:#003CC8;stop-opacity:1\\"/></linearGradient></defs><rect width=\\"20\\" height=\\"20\\" rx=\\"4\\" fill=\\"url(#ind-check-automotive-0)\\"/><path d=\\"M6 10L9 13L14 7\\" stroke=\\"white\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/></svg>OEM EDI integration ready</li>\\n                <li><svg width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 20 20\\" fill=\\"none\\" xmlns=\\"http://www.w3.org/2000/svg\\"><defs><linearGradient id=\\"ind-check-automotive-1\\" x1=\\"0%\\" y1=\\"0%\\" x2=\\"100%\\" y2=\\"100%\\"><stop offset=\\"0%\\" style=\\"stop-color:#00AFF0;stop-opacity:1\\"/><stop offset=\\"100%\\" style=\\"stop-color:#003CC8;stop-opacity:1\\"/></linearGradient></defs><rect width=\\"20\\" height=\\"20\\" rx=\\"4\\" fill=\\"url(#ind-check-automotive-1)\\"/><path d=\\"M6 10L9 13L14 7\\" stroke=\\"white\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/></svg>IATF 16949 compliance support</li>\\n                <li><svg width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 20 20\\" fill=\\"none\\" xmlns=\\"http://www.w3.org/2000/svg\\"><defs><linearGradient id=\\"ind-check-automotive-2\\" x1=\\"0%\\" y1=\\"0%\\" x2=\\"100%\\" y2=\\"100%\\"><stop offset=\\"0%\\" style=\\"stop-color:#00AFF0;stop-opacity:1\\"/><stop offset=\\"100%\\" style=\\"stop-color:#003CC8;stop-opacity:1\\"/></linearGradient></defs><rect width=\\"20\\" height=\\"20\\" rx=\\"4\\" fill=\\"url(#ind-check-automotive-2)\\"/><path d=\\"M6 10L9 13L14 7\\" stroke=\\"white\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/></svg>Lot-level traceability for recalls</li>\\n                <li><svg width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 20 20\\" fill=\\"none\\" xmlns=\\"http://www.w3.org/2000/svg\\"><defs><linearGradient id=\\"ind-check-automotive-3\\" x1=\\"0%\\" y1=\\"0%\\" x2=\\"100%\\" y2=\\"100%\\"><stop offset=\\"0%\\" style=\\"stop-color:#00AFF0;stop-opacity:1\\"/><stop offset=\\"100%\\" style=\\"stop-color:#003CC8;stop-opacity:1\\"/></linearGradient></defs><rect width=\\"20\\" height=\\"20\\" rx=\\"4\\" fill=\\"url(#ind-check-automotive-3)\\"/><path d=\\"M6 10L9 13L14 7\\" stroke=\\"white\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/></svg>Kanban and just-in-time scheduling</li>\\n              </ul>\\n              <a href=\\"/industries/automotive/\\" class=\\"ind-cta\\">Explore Automotive Solutions<svg width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 20 20\\" fill=\\"none\\"><path d=\\"M7 4L13 10L7 16\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/></svg></a>\\n            </div>\\n          </div>\\n        </div>\\n\\n        <div class=\\"ind-tab-content\\" id=\\"ind-tab-electronics\\">\\n          <div class=\\"ind-grid\\">\\n            <div class=\\"ind-image-container\\" id=\\"ind-svg-electronics\\"></div>\\n            <div class=\\"ind-text-content\\">\\n              <h3 class=\\"ind-content-title\\">Electronics Assembly</h3>\\n              <p class=\\"ind-content-desc\\">High-mix, low-volume. Fast product cycles. Thousands of components per board. We built our MES for exactly this complexity.</p>\\n              <ul class=\\"ind-features\\">\\n                <li><svg width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 20 20\\" fill=\\"none\\" xmlns=\\"http://www.w3.org/2000/svg\\"><defs><linearGradient id=\\"ind-check-electronics-0\\" x1=\\"0%\\" y1=\\"0%\\" x2=\\"100%\\" y2=\\"100%\\"><stop offset=\\"0%\\" style=\\"stop-color:#00AFF0;stop-opacity:1\\"/><stop offset=\\"100%\\" style=\\"stop-color:#003CC8;stop-opacity:1\\"/></linearGradient></defs><rect width=\\"20\\" height=\\"20\\" rx=\\"4\\" fill=\\"url(#ind-check-electronics-0)\\"/><path d=\\"M6 10L9 13L14 7\\" stroke=\\"white\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/></svg>SMT (Surface Mount Technology) machine integration</li>\\n                <li><svg width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 20 20\\" fill=\\"none\\" xmlns=\\"http://www.w3.org/2000/svg\\"><defs><linearGradient id=\\"ind-check-electronics-1\\" x1=\\"0%\\" y1=\\"0%\\" x2=\\"100%\\" y2=\\"100%\\"><stop offset=\\"0%\\" style=\\"stop-color:#00AFF0;stop-opacity:1\\"/><stop offset=\\"100%\\" style=\\"stop-color:#003CC8;stop-opacity:1\\"/></linearGradient></defs><rect width=\\"20\\" height=\\"20\\" rx=\\"4\\" fill=\\"url(#ind-check-electronics-1)\\"/><path d=\\"M6 10L9 13L14 7\\" stroke=\\"white\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/></svg>Component-level traceability</li>\\n                <li><svg width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 20 20\\" fill=\\"none\\" xmlns=\\"http://www.w3.org/2000/svg\\"><defs><linearGradient id=\\"ind-check-electronics-2\\" x1=\\"0%\\" y1=\\"0%\\" x2=\\"100%\\" y2=\\"100%\\"><stop offset=\\"0%\\" style=\\"stop-color:#00AFF0;stop-opacity:1\\"/><stop offset=\\"100%\\" style=\\"stop-color:#003CC8;stop-opacity:1\\"/></linearGradient></defs><rect width=\\"20\\" height=\\"20\\" rx=\\"4\\" fill=\\"url(#ind-check-electronics-2)\\"/><path d=\\"M6 10L9 13L14 7\\" stroke=\\"white\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/></svg>MSD (Moisture Sensitivity Device) management</li>\\n                <li><svg width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 20 20\\" fill=\\"none\\" xmlns=\\"http://www.w3.org/2000/svg\\"><defs><linearGradient id=\\"ind-check-electronics-3\\" x1=\\"0%\\" y1=\\"0%\\" x2=\\"100%\\" y2=\\"100%\\"><stop offset=\\"0%\\" style=\\"stop-color:#00AFF0;stop-opacity:1\\"/><stop offset=\\"100%\\" style=\\"stop-color:#003CC8;stop-opacity:1\\"/></linearGradient></defs><rect width=\\"20\\" height=\\"20\\" rx=\\"4\\" fill=\\"url(#ind-check-electronics-3)\\"/><path d=\\"M6 10L9 13L14 7\\" stroke=\\"white\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/></svg>AOI (Automated Optical Inspection) integration and defect tracking</li>\\n              </ul>\\n              <a href=\\"/industries/electronics/\\" class=\\"ind-cta\\">Explore Electronics Solutions<svg width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 20 20\\" fill=\\"none\\"><path d=\\"M7 4L13 10L7 16\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/></svg></a>\\n            </div>\\n          </div>\\n        </div>\\n\\n        <div class=\\"ind-tab-content\\" id=\\"ind-tab-metal-plastics\\">\\n          <div class=\\"ind-grid\\">\\n            <div class=\\"ind-image-container\\" id=\\"ind-svg-metal-plastics\\"></div>\\n            <div class=\\"ind-text-content\\">\\n              <h3 class=\\"ind-content-title\\">Metal & Plastics Processing</h3>\\n              <p class=\\"ind-content-desc\\">Stamping, injection molding, CNC machining. Process manufacturing where yield optimization and scrap reduction drive your margins.</p>\\n              <ul class=\\"ind-features\\">\\n                <li><svg width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 20 20\\" fill=\\"none\\" xmlns=\\"http://www.w3.org/2000/svg\\"><defs><linearGradient id=\\"ind-check-metal-plastics-0\\" x1=\\"0%\\" y1=\\"0%\\" x2=\\"100%\\" y2=\\"100%\\"><stop offset=\\"0%\\" style=\\"stop-color:#00AFF0;stop-opacity:1\\"/><stop offset=\\"100%\\" style=\\"stop-color:#003CC8;stop-opacity:1\\"/></linearGradient></defs><rect width=\\"20\\" height=\\"20\\" rx=\\"4\\" fill=\\"url(#ind-check-metal-plastics-0)\\"/><path d=\\"M6 10L9 13L14 7\\" stroke=\\"white\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/></svg>Process parameter monitoring</li>\\n                <li><svg width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 20 20\\" fill=\\"none\\" xmlns=\\"http://www.w3.org/2000/svg\\"><defs><linearGradient id=\\"ind-check-metal-plastics-1\\" x1=\\"0%\\" y1=\\"0%\\" x2=\\"100%\\" y2=\\"100%\\"><stop offset=\\"0%\\" style=\\"stop-color:#00AFF0;stop-opacity:1\\"/><stop offset=\\"100%\\" style=\\"stop-color:#003CC8;stop-opacity:1\\"/></linearGradient></defs><rect width=\\"20\\" height=\\"20\\" rx=\\"4\\" fill=\\"url(#ind-check-metal-plastics-1)\\"/><path d=\\"M6 10L9 13L14 7\\" stroke=\\"white\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/></svg>Mold/die lifecycle management</li>\\n                <li><svg width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 20 20\\" fill=\\"none\\" xmlns=\\"http://www.w3.org/2000/svg\\"><defs><linearGradient id=\\"ind-check-metal-plastics-2\\" x1=\\"0%\\" y1=\\"0%\\" x2=\\"100%\\" y2=\\"100%\\"><stop offset=\\"0%\\" style=\\"stop-color:#00AFF0;stop-opacity:1\\"/><stop offset=\\"100%\\" style=\\"stop-color:#003CC8;stop-opacity:1\\"/></linearGradient></defs><rect width=\\"20\\" height=\\"20\\" rx=\\"4\\" fill=\\"url(#ind-check-metal-plastics-2)\\"/><path d=\\"M6 10L9 13L14 7\\" stroke=\\"white\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/></svg>Scrap analysis and reduction</li>\\n                <li><svg width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 20 20\\" fill=\\"none\\" xmlns=\\"http://www.w3.org/2000/svg\\"><defs><linearGradient id=\\"ind-check-metal-plastics-3\\" x1=\\"0%\\" y1=\\"0%\\" x2=\\"100%\\" y2=\\"100%\\"><stop offset=\\"0%\\" style=\\"stop-color:#00AFF0;stop-opacity:1\\"/><stop offset=\\"100%\\" style=\\"stop-color:#003CC8;stop-opacity:1\\"/></linearGradient></defs><rect width=\\"20\\" height=\\"20\\" rx=\\"4\\" fill=\\"url(#ind-check-metal-plastics-3)\\"/><path d=\\"M6 10L9 13L14 7\\" stroke=\\"white\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/></svg>Cycle time optimization</li>\\n              </ul>\\n              <a href=\\"/industries/metal-plastics/\\" class=\\"ind-cta\\">Explore Metal & Plastics Solutions<svg width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 20 20\\" fill=\\"none\\"><path d=\\"M7 4L13 10L7 16\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"/></svg></a>\\n            </div>\\n          </div>\\n        </div>\\n      </div>\\n      </div>\\n    </div>\\n    </div>\\n\\n    <script>\\n      function dwSwitchTab_ind(tabName) {\\n        document.querySelectorAll(\'.ind-tab\').forEach(function(tab) {\\n          tab.classList.remove(\'ind-tab-active\');\\n        });\\n        document.querySelectorAll(\'.ind-tab-content\').forEach(function(content) {\\n          content.classList.remove(\'ind-tab-active\');\\n        });\\n        var selectedTab = document.querySelector(\'.ind-tab[data-tab=\\"\' + tabName + \'\\"]\');\\n        var selectedContent = document.getElementById(\'ind-tab-\' + tabName);\\n        if (selectedTab) selectedTab.classList.add(\'ind-tab-active\');\\n        if (selectedContent) selectedContent.classList.add(\'ind-tab-active\');\\n      }\\n      (function(){\\n        function u8(b){return decodeURIComponent(Array.from(atob(b),function(c){return\'%\'+(\'00\'+c.charCodeAt(0).toString(16)).slice(-2)}).join(\'\'))}\\n        var svgs={\\"automotive\\":\\"\\",\\"electronics\\":\\"\\",\\"metal-plastics\\":\\"\\"};\\n        for(var k in svgs){var el=document.getElementById(\'ind-svg-\'+k);if(el&&svgs[k])el.innerHTML=u8(svgs[k]);}\\n        var rm=window.matchMedia(\'(prefers-reduced-motion:reduce)\');\\n        function handleMotion(){\\n          if(rm.matches){\\n            document.querySelectorAll(\'.ind-image-container animate,.ind-image-container animateTransform,.ind-image-container animateMotion\')\\n            .forEach(function(el){el.remove()});\\n          }\\n        }\\n        handleMotion();\\n        if(rm.addEventListener)rm.addEventListener(\'change\',handleMotion);\\n      })();\\n    </script>"}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Industry Tabs: Content"}}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Stats Banner: 6 Key Numbers"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Stats Banner: 6 Key Numbers: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Stats Banner: 6 Key Numbers: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="stats-deco" aria-hidden="true"></div><!-- /wp:html -->\n<!-- wp:html --><div class="stats-section" data-particles="bold">\n    <div class="stats-container">\n      <div class="stats-grid">\n        \n    <div class="stats-item" data-index="0">\n      <div class="stats-number stats-counter" data-target="44">\n        44\n      </div>\n      <div class="stats-label">Years in Manufacturing Software</div>\n    </div>\n    <div class="stats-item" data-index="1">\n      <div class="stats-number stats-counter" data-target="50,000+">\n        50,000+\n      </div>\n      <div class="stats-label">Factory Deployments Across Asia</div>\n    </div>\n    <div class="stats-item" data-index="2">\n      <div class="stats-number stats-counter" data-target="100+">\n        100+\n      </div>\n      <div class="stats-label">Thai Implementations</div>\n    </div>\n    <div class="stats-item" data-index="3">\n      <div class="stats-number stats-counter" data-target="80%">\n        80%\n      </div>\n      <div class="stats-label">of Taiwan\'s Top 2,000 Manufacturers</div>\n    </div>\n    <div class="stats-item" data-index="4">\n      <div class="stats-number stats-counter" data-target="54%">\n        54%\n      </div>\n      <div class="stats-label">Taiwan Manufacturing Solutions Market Share</div>\n    </div>\n    <div class="stats-item" data-index="5">\n      <div class="stats-number" data-target="300378">\n        300378\n      </div>\n      <div class="stats-label">Shenzhen Stock Exchange</div>\n    </div>\n      </div>\n      <div class="stats-source">Source: Common Wealth Magazine, 2023</div>\n    </div>\n    <div class="dw-wave-fade"></div>\n    </div>\n    \n<script>\n(function(){\n  \'use strict\';\n  var reducedMotion=window.matchMedia(\'(prefers-reduced-motion: reduce)\').matches;\n  var PI2=Math.PI*2;\n  var BLUE=[0,175,240],CYAN=[0,230,255];\n  var PRESETS={\n    subtle:{frontOpacity:0.30,backOpacity:0.04,frontRadius:4.5,backRadius:0.6,color:BLUE,colorAlt:CYAN,altRatio:0.12},\n    medium:{frontOpacity:0.45,backOpacity:0.06,frontRadius:5.0,backRadius:0.8,color:BLUE,colorAlt:CYAN,altRatio:0.18},\n    bold:{frontOpacity:0.60,backOpacity:0.10,frontRadius:5.5,backRadius:1.0,color:CYAN,colorAlt:BLUE,altRatio:0.25}\n  };\n  function lerp(a,b,t){return a+(b-a)*t}\n  function DataOcean(el){\n    this.el=el;this.canvas=null;this.ctx=null;this.w=0;this.h=0;\n    this.dpr=Math.min(window.devicePixelRatio||1,2);this.visible=false;this.raf=null;this.time=0;this.resizeTimer=null;this.colors=null;\n    this.opts=this._parseOpts();this._setup();this._buildColors();this._observe();\n    if(!reducedMotion){this._loop()}else{this.visible=true;this._draw(0)}\n  }\n  DataOcean.prototype._parseOpts=function(){var n=this.el.getAttribute(\'data-particles\')||\'subtle\';if(n===\'\'||n===\'true\')n=\'subtle\';return PRESETS[n]||PRESETS.subtle};\n  DataOcean.prototype._setup=function(){\n    var c=document.createElement(\'canvas\');c.setAttribute(\'aria-hidden\',\'true\');\n    c.style.cssText=\'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;\';\n    var pos=getComputedStyle(this.el).position;if(pos===\'static\')this.el.style.position=\'relative\';\n    this.el.style.overflow=\'hidden\';this.el.insertBefore(c,this.el.firstChild);this.canvas=c;this.ctx=c.getContext(\'2d\');this._resize();\n    var self=this;window.addEventListener(\'resize\',function(){clearTimeout(self.resizeTimer);self.resizeTimer=setTimeout(function(){self._resize();self._buildColors()},200)});\n  };\n  DataOcean.prototype._resize=function(){var r=this.el.getBoundingClientRect();this.w=r.width;this.h=r.height;this.canvas.width=this.w*this.dpr;this.canvas.height=this.h*this.dpr;this.ctx.setTransform(this.dpr,0,0,this.dpr,0,0)};\n  DataOcean.prototype._buildColors=function(){var cols=Math.min(65,Math.ceil(this.w/22)+4);var rows=35;this._cols=cols;this._rows=rows;var n=cols*rows;this.colors=new Array(n);var alt=this.opts.altRatio;for(var i=0;i<n;i++){this.colors[i]=Math.random()<alt?this.opts.colorAlt:this.opts.color}};\n  DataOcean.prototype._observe=function(){var self=this;if(\'IntersectionObserver\' in window){this._obs=new IntersectionObserver(function(e){self.visible=e[0].isIntersecting},{rootMargin:\'150px 0px\'});this._obs.observe(this.el)}else{this.visible=true}};\n  DataOcean.prototype._loop=function(){var self=this;var last=0;(function tick(ts){self.raf=requestAnimationFrame(tick);if(!self.visible)return;if(ts-last<30)return;last=ts;self.time+=0.006;self._draw(self.time)})(0)};\n  DataOcean.prototype._draw=function(t){\n    var ctx=this.ctx,w=this.w,h=this.h,opts=this.opts,cols=this._cols,rows=this._rows;\n    ctx.clearRect(0,0,w,h);var ground=h+10,horizon=h*0.35,totalSpan=ground-horizon,idx=0;\n    for(var row=rows-1;row>=0;row--){\n      var depth=row/(rows-1),mappedDepth=Math.pow(depth,0.55),baseY=ground-mappedDepth*totalSpan;\n      var dotR=lerp(opts.frontRadius,opts.backRadius,depth),dotA=lerp(opts.frontOpacity,opts.backOpacity,depth);\n      var colSpacing=lerp(w/(cols-4),w/(cols+15),depth),rowShift=depth*w*0.12;\n      var waveScale=1-depth*0.75,amp1=70*waveScale,amp2=25*waveScale;\n      for(var col=0;col<cols;col++){\n        var screenX=col*colSpacing-rowShift+colSpacing*0.5;\n        if(screenX<-30||screenX>w+30){idx++;continue}\n        var worldX=col*24,worldZ=row*18;\n        var wave=amp1*Math.sin(worldX*0.0065+worldZ*0.012+t*0.9);\n        wave+=amp2*Math.sin(worldX*0.013-worldZ*0.008+t*0.55+1.8);\n        var screenY=baseY-wave;if(screenY<-15||screenY>h+15){idx++;continue}\n        var c=this.colors[idx%this.colors.length];\n        ctx.beginPath();ctx.arc(screenX,screenY,dotR,0,PI2);\n        ctx.fillStyle=\'rgba(\'+c[0]+\',\'+c[1]+\',\'+c[2]+\',\'+dotA+\')\';ctx.fill();idx++;\n      }\n    }\n  };\n  DataOcean.prototype.destroy=function(){if(this.raf)cancelAnimationFrame(this.raf);if(this._obs)this._obs.disconnect();if(this.canvas&&this.canvas.parentNode)this.canvas.parentNode.removeChild(this.canvas)};\n  function init(){var els=document.querySelectorAll(\'[data-particles]\');for(var i=0;i<els.length;i++)new DataOcean(els[i])}\n  if(document.readyState===\'loading\')document.addEventListener(\'DOMContentLoaded\',init);else init();\n})();\n</script>\n    \n<script>\n(function() {\n  var counters = document.querySelectorAll(\'.stats-counter\');\n  var animated = false;\n  function animateCounter(el) {\n    var target = el.getAttribute(\'data-target\');\n    var isPercentage = target.indexOf(\'%\') !== -1;\n    var hasPlus = target.indexOf(\'+\') !== -1;\n    var hasComma = target.indexOf(\',\') !== -1;\n    var numericTarget = parseFloat(target.replace(/[^0-9.]/g, \'\'));\n    var current = 0;\n    var increment = numericTarget / 60;\n    var frameRate = 1000 / 60;\n    el.classList.add(\'counting\');\n    var timer = setInterval(function() {\n      current += increment;\n      if (current >= numericTarget) { current = numericTarget; clearInterval(timer); }\n      var displayValue = Math.floor(current).toString();\n      if (hasComma && current >= 1000) displayValue = displayValue.replace(/\\B(?=(\\d{3})+(?!\\d))/g, \',\');\n      if (hasPlus) displayValue += \'+\';\n      if (isPercentage) displayValue += \'%\';\n      el.textContent = displayValue;\n    }, frameRate);\n  }\n  function checkScroll() {\n    if (animated) return;\n    var section = document.querySelector(\'.stats-container\');\n    if (!section) return;\n    var rect = section.getBoundingClientRect();\n    if (rect.top < window.innerHeight * 0.75 && rect.bottom > 0) {\n      animated = true;\n      counters.forEach(function(counter, index) {\n        setTimeout(function() { animateCounter(counter); }, index * 100);\n      });\n    }\n  }\n  if (document.readyState === \'loading\') document.addEventListener(\'DOMContentLoaded\', checkScroll);\n  else checkScroll();\n  window.addEventListener(\'scroll\', function() { checkScroll(); }, { passive: true });\n  setTimeout(function() { if (!animated) { animated = true; counters.forEach(function(c,i) { setTimeout(function() { animateCounter(c); }, i * 100); }); } }, 3000);\n  var years = new Date().getFullYear() - 1982;\n  document.querySelectorAll(\'.dw-years\').forEach(function(el) { el.textContent = years; });\n  var yearStat = document.querySelector(\'.stats-counter[data-target="44"]\');\n  if (yearStat) yearStat.setAttribute(\'data-target\', String(years));\n})();\n</script><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Trust Anchors: 5 Credibility Cards"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Trust Anchors: 5 Credibility Cards: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Trust Anchors: 5 Credibility Cards: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="trust-section">\n    <div class="trust-scene"><svg viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice">\n    <path d="M250 180 L250 380 Q250 480 350 530 Q450 480 450 380 L450 180 L350 140Z" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n    <path d="M320 300 L345 325 L400 270" stroke="#00AFF0" stroke-width="2.5" fill="none" opacity="0.2"/>\n    <path d="M600 400 L650 380 L700 420 L750 350 L800 370 L850 300 L900 320 L950 280 L1000 300 L1050 260 L1100 280" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.15"/>\n    <text x="1110" y="285" font-family="\'Noto Sans\',sans-serif" font-size="12" font-weight="700" fill="#000864" opacity="0.1">300378</text>\n    <circle cx="1250" cy="200" r="45" stroke="#000864" stroke-width="2" fill="none" opacity="0.12"/>\n    <circle cx="1250" cy="200" r="35" stroke="#000864" stroke-width="1" fill="none" opacity="0.08"/>\n    <text x="1250" y="205" font-family="\'Noto Sans\',sans-serif" font-size="10" font-weight="700" fill="#000864" opacity="0.1" text-anchor="middle">ISO</text>\n    <line x1="100" y1="750" x2="1300" y2="750" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n    <line x1="100" y1="740" x2="100" y2="760" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n    <line x1="400" y1="740" x2="400" y2="760" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n    <line x1="700" y1="740" x2="700" y2="760" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n    <line x1="1000" y1="740" x2="1000" y2="760" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n    <line x1="1300" y1="740" x2="1300" y2="760" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n    <text x="100" y="780" font-family="\'Noto Sans\',sans-serif" font-size="11" fill="#000864" opacity="0.08" text-anchor="middle">1982</text>\n    <text x="700" y="780" font-family="\'Noto Sans\',sans-serif" font-size="11" fill="#000864" opacity="0.08" text-anchor="middle">2006</text>\n    <text x="1300" y="780" font-family="\'Noto Sans\',sans-serif" font-size="11" fill="#000864" opacity="0.08" text-anchor="middle">2026</text>\n    <circle cx="800" cy="150" r="60" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.1"/>\n    <ellipse cx="800" cy="150" rx="30" ry="60" stroke="#000864" stroke-width="1" fill="none" opacity="0.07"/>\n    <line x1="740" y1="150" x2="860" y2="150" stroke="#000864" stroke-width="1" opacity="0.07"/>\n    <circle cx="780" cy="135" r="3" fill="#00AFF0" opacity="0.2"/>\n    <circle cx="820" cy="160" r="3" fill="#00AFF0" opacity="0.15"/>\n    <circle cx="790" cy="170" r="2.5" fill="#00AFF0" opacity="0.12"/>\n    <circle cx="500" cy="500" r="3" fill="#000864" opacity="0.1"/>\n    <circle cx="1100" cy="600" r="4" fill="#000864" opacity="0.07"/>\n    <circle cx="150" cy="550" r="3" fill="#000864" opacity="0.08"/>\n  </svg></div>\n    \n    <div class="trust-header">\n      <div class="trust-header-label">Why Trust DigiWin</div>\n      <h2 class="trust-title">Credibility Without Hype</h2>\n      <p class="trust-subtitle">We don’t just claim to be different. Here’s the evidence.</p>\n    </div>\n    <div class="trust-grid">\n    <div class="trust-card">\n      <div class="trust-bg-icon"><svg width="180" height="180" viewBox="0 0 24 24" fill="none" stroke="#00AFF0" stroke-width="1"><path d="M3 3v18h18"/><path d="M18 17V9"/><path d="M13 17V5"/><path d="M8 17v-3"/></svg></div>\n      \n      <div class="trust-card-icon"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#00AFF0" stroke-width="1.5"><path d="M3 3v18h18"/><path d="M18 17V9"/><path d="M13 17V5"/><path d="M8 17v-3"/></svg></div>\n      <div class="trust-badge">300378</div>\n      \n      <h3 class="trust-card-title">Financial Stability</h3>\n      \n      <p class="trust-headline">We are a publicly traded company with transparent financials—the stability partners and clients need for a 10-year relationship.</p>\n      \n      <p class="trust-detail">Our financials are publicly audited and regulated by the Shenzhen Stock Exchange. That means you’re partnering with a company that has the governance, capital, and long-term commitment to support your factory for years to come — not a vendor that might disappear after implementation.</p>\n    </div>\n    <div class="trust-card">\n      <div class="trust-bg-icon"><svg width="180" height="180" viewBox="0 0 24 24" fill="none" stroke="#00AFF0" stroke-width="1"><path d="M12 2L2 7l10 5 10-5-10-5z"/><path d="M2 17l10 5 10-5"/><path d="M2 12l10 5 10-5"/></svg></div>\n      \n      <div class="trust-card-icon"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#00AFF0" stroke-width="1.5"><path d="M12 2L2 7l10 5 10-5-10-5z"/><path d="M2 17l10 5 10-5"/><path d="M2 12l10 5 10-5"/></svg></div>\n      <div class="trust-badge">Foxconn FII</div>\n      \n      <h3 class="trust-card-title">Manufacturing DNA</h3>\n      \n      <p class="trust-headline">Strategic investment from Foxconn Industrial Internet — validation that our software meets the standards of the world’s largest electronics manufacturer.</p>\n      \n      <p class="trust-detail">This isn’t generic IT software — it’s built for industrial reality. When the company that manufactures iPhones trusts DigiWin on their production lines, that speaks to the depth and reliability of our platform at the highest level of manufacturing complexity.</p>\n    </div>\n    <div class="trust-card">\n      <div class="trust-bg-icon"><svg width="180" height="180" viewBox="0 0 24 24" fill="none" stroke="#00AFF0" stroke-width="1"><circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/></svg></div>\n      \n      <div class="trust-card-icon"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#00AFF0" stroke-width="1.5"><circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/></svg></div>\n      <div class="trust-badge">Since 1982</div>\n      \n      <h3 class="trust-card-title">Manufacturing Focus Since Day One</h3>\n      \n      <p class="trust-headline">We have spent <span class="dw-years">44</span> years exclusively in manufacturing software—built on decades of shop-floor reality, not temporary tech trends.</p>\n      \n      <p class="trust-detail">DigiWin has survived every technology shift (DOS → Windows → Cloud) while staying focused on manufacturing. We didn’t pivot to crypto or retail POS when it was trendy.</p>\n    </div>\n    <div class="trust-card">\n      <div class="trust-bg-icon"><svg width="180" height="180" viewBox="0 0 24 24" fill="none" stroke="#00AFF0" stroke-width="1"><circle cx="12" cy="12" r="10"/><path d="M2 12h20"/><path d="M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z"/></svg></div>\n      \n      <div class="trust-card-icon"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#00AFF0" stroke-width="1.5"><circle cx="12" cy="12" r="10"/><path d="M2 12h20"/><path d="M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z"/></svg></div>\n      <div class="trust-badge">50,000+</div>\n      \n      <h3 class="trust-card-title">Proven at Scale</h3>\n      \n      <p class="trust-headline">Our methodology is refined from 50,000+ implementations across Asia—adopt a proven standard, not a beta product.</p>\n      \n      <p class="trust-detail">The software has been refined through thousands of real-world factory deployments across Asia. It handles the specific complexities — Thai tax rules, sub-contracting workflows, circular bills of materials — that often break smaller systems.</p>\n    </div>\n    <div class="trust-card trust-card--full">\n      <div class="trust-bg-icon"><svg width="180" height="180" viewBox="0 0 24 24" fill="none" stroke="#00AFF0" stroke-width="1"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/><path d="M9 12l2 2 4-4"/></svg></div>\n      \n      <div class="trust-card-icon"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#00AFF0" stroke-width="1.5"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/><path d="M9 12l2 2 4-4"/></svg></div>\n      <div class="trust-badge">BOI Ready</div>\n      \n      <h3 class="trust-card-title">BOI Compliance</h3>\n      \n      <p class="trust-headline">Production-order-level material reconciliation that passes BOI (Board of Investment) audits — a capability no competitor can match.</p>\n      \n      <p class="trust-detail">One factory saved 10M+ THB/year in supplementary taxes. Our system tracks actual material consumption per production order, not theoretical bill-of-materials calculations — the gap that triggers costly audit findings. <a href="/blog/" style="color:#0369a1">Read the full story →</a></p>\n    </div></div>\n    \n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proven Results: 2 Case Studies"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proven Results: 2 Case Studies: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proven Results: 2 Case Studies: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="results-section">\n    <div class="results-container">\n      \n    <div class="results-header">\n      <div class="results-header-label">Proven Results</div>\n      <h2 class="results-title">Real Outcomes from Thai Factories</h2>\n      <p class="results-subtitle">These aren’t projections. These are results our clients achieved after going live.</p>\n    </div>\n      <div class="results-grid">\n        \n    <div class="results-card">\n      <div class="results-company">Thai Alpha Polymer</div>\n      <div class="results-metric">Month-end closing: 60 days to 15 days</div>\n      <p class="results-detail">Stock accuracy reached 95% with Workflow ERP + WMS integration across their PET plastic roll operations.</p>\n    </div>\n  \n    <div class="results-card">\n      <div class="results-company">Ginfong Precision Metal Stamping</div>\n      <div class="results-metric">Revenue growth of 200%, margins from 23% to 34%</div>\n      <p class="results-detail">Gross profit improved from 23% to 34% with ERP + SFT (Shop Floor Tracking) — even during the COVID period when competitors contracted.</p>\n    </div>\n  \n      </div>\n      <div class="results-cta"><a href="/case-studies/" class="results-link">See all case studies →</a></div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Final CTA: Let\'s Start a Conversation"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Final CTA: Let\'s Start a Conversation: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Final CTA: Let\'s Start a Conversation: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="cta-section">\n    <div class="cta-super-d" aria-hidden="true"></div>\n    <div class="cta-wave-flow" aria-hidden="true"></div>\n    <div class="cta-container">\n      <h2 class="cta-title">Let’s Start a Conversation</h2>\n      <p class="cta-subtitle">We’re eager to understand your challenges and explore how we can help. No pressure, no sales pitch—just a genuine conversation about your manufacturing operations.</p>\n      <div class="cta-btn-row">\n        <a href="/demo/" class="cta-btn cta-btn--primary">Let’s Talk</a>\n        <a href="/partner-program/" class="cta-btn cta-btn--ghost">Explore Partnership</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100684;

