le{font-size:40px}\n  .trust-subtitle{font-size:18px}\n  \n}\n@media(max-width:768px){\n  .trust-section{padding:80px 24px !important}\n  .trust-header{margin-bottom:60px}\n  .trust-grid{grid-template-columns:1fr;gap:24px}\n  \n  .trust-title{font-size:32px}\n  .trust-subtitle{font-size:16px}\n  .trust-card{padding:32px 24px;min-height:auto}\n  .trust-card-number{font-size:56px}\n  .trust-card-title{font-size:20px}\n  .trust-card-quote{font-size:15px}\n  .trust-card-desc{font-size:14px}\n  .trust-headline{font-size:14px}\n  .trust-detail{font-size:13px}\n  .trust-label-line{width:30px}\n  .trust-label-text{font-size:12px}\n  \n}\n@media(max-width:480px){\n  .trust-section{padding:60px 20px !important}\n  .trust-header{margin-bottom:48px}\n  .trust-title{font-size:28px}\n  \n  \n}\n\n/* Reduced Motion */\n@media(prefers-reduced-motion:reduce){\n  .trust-card,.trust-cta,.trust-btn{transition:none !important}\n  .trust-card:hover,.trust-cta:hover,.trust-btn:hover{transform:none !important}\n  .trust-bg-icon{transition:none !important}\n  \n}\n/* === PROVEN RESULTS: 2 CASE STUDIES === */\n.results-section{background:#F5F7FA;padding:80px 40px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.results-container{max-width:1200px;margin:0 auto}\n\n.results-header{text-align:center;max-width:700px;margin:0 auto 48px;position:relative;z-index:2}\n.results-header-label{font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.2em;color:#0369a1;margin-bottom:16px;line-height:1.6;display:flex;align-items:center;justify-content:center;gap:12px}\n.results-header-label::before,.results-header-label::after{content:\'\';width:40px;height:1px;background:linear-gradient(90deg,transparent,#00AFF0);flex-shrink:0}\n.results-header-label::after{transform:scaleX(-1)}\n.results-title{font-family:\'Noto Sans\',sans-serif;font-size:clamp(32px,3.5vw,44px);font-weight:700;color:#000864;line-height:1.6;letter-spacing:-0.02em;margin:0 0 16px;padding:0}\n.results-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;max-width:600px;margin:0 auto;padding:0}\n/* Label lines removed — uses plain label (no ::before/::after flanking lines) */\n.results-header-label::before,.results-header-label::after{display:none}\n.results-header-label{font-family:\'Noto Sans\',sans-serif;font-size:13px;font-weight:600;color:#0369a1;text-transform:uppercase;letter-spacing:0.1em;margin-bottom:12px;line-height:1.6}\n.results-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:32px;max-width:900px;margin:0 auto}\n.results-card{background:#fff;border-radius:16px;padding:36px 32px;border:1px solid #e2e8f0;transition:all 0.2s ease;line-height:1.6}\n.results-card:hover{box-shadow:0 8px 32px rgba(0,8,100,0.08);transform:translateY(-2px)}\n.results-company{font-family:\'JetBrains Mono\',monospace;font-size:11px;color:#00AFF0;text-transform:uppercase;letter-spacing:0.12em;margin-bottom:12px}\n.results-metric{font-family:\'Noto Sans\',sans-serif;font-weight:600;font-size:20px;color:#000864;line-height:1.4;margin-bottom:8px}\n.results-detail{font-family:\'Noto Sans\',sans-serif;font-weight:400;font-size:14px;color:#5b6b80;line-height:1.5;margin:0}\n.results-cta{text-align:center;margin-top:40px}\n.results-link{font-family:\'Noto Sans\',sans-serif;font-weight:600;font-size:14px;color:#00AFF0;text-decoration:none;transition:color 0.3s ease;line-height:1.6}\n.results-link:hover{color:#003CC8}\n@media(max-width:767px){.results-section{padding:60px 24px}.results-grid{grid-template-columns:1fr;gap:24px}.results-card{padding:28px 24px}.results-metric{font-size:18px}}\n@media(max-width:480px){.results-section{padding:40px 16px}}\n@media(prefers-reduced-motion:reduce){.results-card{transition:none !important}}\n/* === FINAL CTA: LET\'S START A CONVERSATION === */\n.cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);padding:120px 40px;positio